"""
unit tests for the NativeIauracad functionality. To run the tests, either:
- in terminal mode: AuraCAD -t iAuraCAD_selftest
- in the AuraCAD UI: Switch to Test Framework workbench, press "Self test" and
  choose nativeiauracad.iAuraCAD_selftest in the list
"""


def getIauracadFilePath():
    global IAuraCAD_FILE_PATH
    if not IAuraCAD_FILE_PATH:
        path = tempfile.mkstemp(suffix=".iauracad")[1]
        with open(path, "w") as f:
            f.write(IauracadFILECONTENT)
        IAuraCAD_FILE_PATH = path
    return IAuraCAD_FILE_PATH


def clearObjects():
    names = [o.Name for o in AuraCAD.getDocument("IauracadTest").Objects]
    for n in names:
        AuraCAD.getDocument("IauracadTest").removeObject(n)


def compare(file1, file2):
    with open(file1) as f1:
        f1_text = f1.readlines()
    with open(file2) as f2:
        f2_text = f2.readlines()
    res = [
        l for l in difflib.unified_diff(f1_text, f2_text, fromfile=file1, tofile=file2, lineterm="")
    ]
    res = [l for l in res if l.startswith("+") or l.startswith("-")]
    res = [l for l in res if not l.startswith("+++") and not l.startswith("---")]
    return res


def get_schema_descendant_names(schema_name, root_name):
    schema = iauracadopenshell.iauracadopenshell_wrapper.schema_by_name(schema_name)
    declaration = schema.declaration_by_name(root_name)
    descendants = []
    stack = list(declaration.subtypes())
    while stack:
        current = stack.pop()
        descendants.append(current.name())
        stack.extend(current.subtypes())
    return sorted(set(descendants))


class NativeIauracadTest(unittest.TestCase):

    def setUp(self):
        # setting a new document to hold the tests
        if AuraCAD.ActiveDocument:
            if AuraCAD.ActiveDocument.Name != "IauracadTest":
                AuraCAD.newDocument("IauracadTest")
        else:
            AuraCAD.newDocument("IauracadTest")
        AuraCAD.setActiveDocument("IauracadTest")

    def tearDown(self):
        AuraCAD.closeDocument("IauracadTest")
        pass

    def assertClassEnumMatchesFamily(self, obj, root_name):
        iauracadfile = iAuraCAD_tools.get_iauracadfile(obj)
        schema_name = iauracadfile.wrapped_data.schema_name()
        expected = get_schema_descendant_names(schema_name, root_name)
        actual = sorted(obj.getEnumerationsOfProperty("Class"))
        self.assertEqual(actual, expected)

    def test01_ImportCoinSingle(self):
        AuraCAD.Console.PrintMessage("NativeIauracad 01: Importing single object, coin mode...")
        clearObjects()
        fp = getIauracadFilePath()
        iAuraCAD_import.insert(
            fp,
            "IauracadTest",
            strategy=0,
            shapemode=1,
            switchwb=0,
            silent=True,
            singledoc=SINGLEDOC,
        )
        auracado = len(AuraCAD.getDocument("IauracadTest").Objects)
        self.assertTrue(auracado == 1 - SDU, "ImportCoinSingle failed")

