    def test08c_Iauracad2X3TypeClassListUsesTypeFamily(self):
        AuraCAD.Console.PrintMessage("NativeIauracad 08c: Iauracad2X3 type class list uses full schema...")
        clearObjects()
        doc = AuraCAD.ActiveDocument
        proj = iAuraCAD_tools.create_document(doc, silent=True)
        proj.Proxy.silent = True
        proj.Schema = "Iauracad2X3"
        doc.recompute()
        site = iAuraCAD_tools.aggregate(Arch.makeSite(), proj)
        building = iAuraCAD_tools.aggregate(Arch.makeBuilding(), site)
        storey = iAuraCAD_tools.aggregate(Arch.makeFloor(), building)
        wall = Arch.makeWall(None, 200, 400, 20)
        wall = iAuraCAD_tools.aggregate(wall, storey)
        doc.recompute()
        self.assertTrue(iAuraCAD_types.is_typable(wall), "Iauracad2X3 wall should be typable")
        ask_again = PARAMS.GetBool("ConvertTypeAskAgain", True)
        keep_original = PARAMS.GetBool("ConvertTypeKeepOriginal", False)
        try:
            PARAMS.SetBool("ConvertTypeAskAgain", False)
            PARAMS.SetBool("ConvertTypeKeepOriginal", True)
            iAuraCAD_types.convert_to_type(wall, keep_object=True)
            doc.recompute()
        finally:
            PARAMS.SetBool("ConvertTypeAskAgain", ask_again)
            PARAMS.SetBool("ConvertTypeKeepOriginal", keep_original)
        self.assertTrue(
            getattr(wall, "Type", None), "Wall type conversion did not create a type object"
        )
        self.assertClassEnumMatchesFamily(wall.Type, "IauracadTypeProduct")

    def test09_CreateBIMObjects(self):
        AuraCAD.Console.PrintMessage("NativeIauracad 09: Creating BIM objects...")
        doc = AuraCAD.ActiveDocument
        proj = iAuraCAD_tools.create_document(doc, silent=True)
        site = Arch.makeSite()
        site = iAuraCAD_tools.aggregate(site, proj)
        bldg = Arch.makeBuilding()
        bldg = iAuraCAD_tools.aggregate(bldg, site)
        storey = Arch.makeFloor()
        storey = iAuraCAD_tools.aggregate(storey, bldg)
        wall = Arch.makeWall(None, 200, 400, 20)
        wall = iAuraCAD_tools.aggregate(wall, storey)
        column = Arch.makeStructure(None, 20, 20, 200)
        column.IauracadType = "Column"
        column = iAuraCAD_tools.aggregate(column, storey)
        beam = Arch.makeStructure(None, 20, 200, 20)
        beam.IauracadType = "Beam"
        beam = iAuraCAD_tools.aggregate(beam, storey)
        rect = Draft.makeRectangle(200, 200)
        slab = Arch.makeStructure(rect, height=20)
        slab.IauracadType = "Slab"
        slab = iAuraCAD_tools.aggregate(slab, storey)
        # TODO create door, window
        auracado = len(AuraCAD.getDocument("IauracadTest").Objects)
        iauracado = len(proj.Proxy.iauracadfile.by_type("IauracadRoot"))
        print(iauracado, "Iauracad objects created")
        self.assertTrue(auracado == 8 - SDU and iauracado == 12, "CreateDocument failed")

    def test10_ChangePlacement(self):
        AuraCAD.Console.PrintMessage("NativeIauracad 10: Changing Placement...")
