    def test13b_MaterialLayerLogical(self):
        AuraCAD.Console.PrintMessage("NativeIauracad 13b: Material layer logical values...")
        clearObjects()
        proj = iAuraCAD_tools.create_document(AuraCAD.getDocument("IauracadTest"), silent=True)
        iauracadfile = iAuraCAD_tools.get_iauracadfile(proj)
        material_set = iAuraCAD_tools.api_run(
            "material.add_material_set",
            iauracadfile,
            name="Layer Set",
            set_type="IauracadMaterialLayerSet",
        )
        material = iAuraCAD_tools.api_run("material.add_material", iauracadfile, name="Layer Material")
        layer_unknown = iAuraCAD_tools.api_run(
            "material.add_layer",
            iauracadfile,
            layer_set=material_set,
            material=material,
            name="Unknown Layer",
        )
        iAuraCAD_tools.api_run(
            "material.edit_layer",
            iauracadfile,
            layer=layer_unknown,
            attributes={"LayerThickness": 42, "IsVentilated": "UNKNOWN"},
        )
        layer_true = iAuraCAD_tools.api_run(
            "material.add_layer",
            iauracadfile,
            layer_set=material_set,
            material=material,
            name="True Layer",
        )
        iAuraCAD_tools.api_run(
            "material.edit_layer",
            iauracadfile,
            layer=layer_true,
            attributes={"LayerThickness": 21, "IsVentilated": True},
        )
        iAuraCAD_materials.create_material(material_set, proj, recursive=True)
        layer_unknown_obj = iAuraCAD_tools.get_object(layer_unknown, AuraCAD.getDocument("IauracadTest"))
        layer_true_obj = iAuraCAD_tools.get_object(layer_true, AuraCAD.getDocument("IauracadTest"))
        self.assertTrue(layer_unknown_obj is not None, "Logical UNKNOWN layer import failed")
        self.assertTrue(layer_true_obj is not None, "Logical TRUE layer import failed")
        self.assertTrue(
            layer_unknown_obj.getTypeIdOfProperty("IsVentilated") == "App::PropertyBool",
            "Logical UNKNOWN type failed",
        )
        self.assertTrue(
            layer_true_obj.getTypeIdOfProperty("IsVentilated") == "App::PropertyBool",
            "Logical TRUE type failed",
        )
        self.assertTrue(layer_unknown_obj.IsVentilated is False, "Logical UNKNOWN value failed")
        self.assertTrue(layer_true_obj.IsVentilated is True, "Logical TRUE value failed")

